      </div>
      {status === "online" && (
        <div className="flex items-center gap-2 text-xs text-[hsl(var(--success))]">
          <Wifi className="h-3.5 w-3.5" />
          <span className="font-semibold">Agent "{agentName}" is online and connected!</span>
