async function checkForUpdate(agentId: string, forceApply = false, bypassIdleCheck = false): Promise<void> {
  if (state.updating) {
    logger.debug("Update already in progress, skipping check");
    return;
  }

  try {
    logger.info("Checking for updates...");
    const info = await api.getLatestBuild();

    // Clear any previous error — we successfully contacted the server
    state.lastError = null;
    state.lastCheckAt = new Date().toISOString();
    state.latestVersion = info.latest_version;

    const currentVersion = config.version;
    const newer = isNewer(info.latest_version, currentVersion);

    state.updateAvailable = newer;

    if (!newer && !forceApply) {
      logger.info("Already on latest version", {
        current: currentVersion,
        latest: info.latest_version,
      });
      return;
    }

    if (newer) {
      logger.info("Update available", {
        current: currentVersion,
        latest: info.latest_version,
      });
    }

    // Wait for idle (no active render jobs) — unless bypass requested
    if (!bypassIdleCheck && activeJobsRef() > 0) {
      logger.info("Deferring update — render jobs active", {
        activeJobs: activeJobsRef(),
      });
      setTimeout(() => checkForUpdate(agentId, forceApply), 30_000);
      return;
    }
    if (bypassIdleCheck && activeJobsRef() > 0) {
      logger.warn("Forcing update despite active render jobs (force_apply_update command)", {
        activeJobs: activeJobsRef(),
      });
    }

    await applyUpdate(info, agentId);
  } catch (e) {
    const msg = (e as Error).message;
    state.lastError = msg;
    logger.error("Update check failed", { error: msg });
  }
}

async function applyUpdate(info: UpdateInfo, agentId: string): Promise<void> {
  state.updating = true;
  state.lastError = null;

  const installDir = getInstallDir();
  const distDir = path.join(installDir, "dist");
  const distOldDir = path.join(installDir, "dist.old");
  const distNewDir = path.join(installDir, "dist.new");
  const zipPath = path.join(installDir, "dist-update.zip");

  try {
    // 1. Download dist.zip
    logger.info("Downloading update...", { url: info.download_url });

      // Full-library PDF/.ai backfill (self-driven claim loop — no asset list passed).
      // Runs the entire mupdf→OCR→AI extraction on this Windows VM so the load stays off
      // the Synology. runPdfBackfill never throws; the finally just clears the guard.
      if (response.commands?.trigger_pdf_backfill && !isBackfillingPdfText) {
        const mountRoot = cloudNasMountPath.trim() || `\\\\${cloudNasHost}\\${cloudNasShare}`;
        isBackfillingPdfText = true;
        logger.info("PDF backfill requested via heartbeat");
        runPdfBackfill(mountRoot, {
          models: cloudAiModels,
          pdf_extraction: cloudPdfExtractionConfig,
          googleApiKey: cloudGoogleAiApiKey,
          anthropicApiKey: cloudAnthropicApiKey,
          openRouterApiKey: cloudOpenRouterApiKey,
          aiTaskModels: cloudAiTaskModels,
        }).catch((e) =>
          logger.error("PDF backfill error", { error: (e as Error).message })
        ).finally(() => {
          isBackfillingPdfText = false;
        });
      }

      // Check if cloud requests immediate update (standard — respects idle check)
      if (response.commands?.trigger_update) {
        logger.info("Cloud requested immediate update check");
        triggerImmediateUpdate(agentId).catch((e) =>
          logger.error("Triggered update failed", { error: (e as Error).message })
        );
      }

      // Force apply update — bypass activeJobs guard
      if (response.commands?.force_apply_update) {
        logger.info("Cloud requested force update — bypassing active-jobs guard");
        triggerImmediateUpdate(agentId, true).catch((e) =>
          logger.error("Force update failed", { error: (e as Error).message })
        );
      }

      // Force restart — exit immediately, launcher restarts us
      if (response.commands?.force_restart) {
        logger.info("Cloud requested force restart — exiting now");
        process.exit(RESTART_EXIT_CODE);
      }

      // Force stop jobs — stop claiming, drain current jobs, then restart
      if (response.commands?.force_stop_jobs) {
        logger.info("Cloud requested stop — halting job claims and draining");
        stopAcceptingJobs = true;
        waitForIdleThenRestart();
      }

